kubectl patch statefulset mongodb-replica -n mongodb --type='json' -p='[
  {
    "op": "add",
    "path": "/spec/template/spec/initContainers",
    "value": [
      {
        "name": "repair-if-unclean",
        "image": "mongo:6.0.5",
        "securityContext": {"runAsUser": 0, "runAsGroup": 0},
        "command": [
          "sh", "-c",
          "if [ -s /data/db/mongod.lock ]; then echo \"Non-empty lock file detected, running repair...\"; mongod --repair --dbpath /data/db --wiredTigerJournalCompressor snappy; echo \"Repair complete.\"; else echo \"Lock file empty or absent, no repair needed.\"; fi"
        ],
        "volumeMounts": [
          {"name": "data-volume", "mountPath": "/data/db"},
          {"name": "mongo-keyfile", "mountPath": "/etc/mongo-keyfile", "readOnly": true}
        ]
      }
    ]
  }
]' 2>&1

